SELECT n.*,
       nc.name AS category_name,
       u1.real_name AS reviewer_name,
       a.title AS related_activity_title
FROM news n
LEFT JOIN news_category nc ON n.category_id = nc.id
LEFT JOIN user u1 ON n.reviewer_id = u1.id
LEFT JOIN activity a ON n.related_activity_id = a.id

